/// <summary>
/// Single-pass collection formatting: applies the formatter, trims, filters blanks,
/// and builds the result string without intermediate LINQ chains.
/// </summary>
private string HumanizeDisplayStrings<T>(
    IEnumerable<T> source, Func<T, string?> formatter, string separator)
{
    var items = new List<string>();
    foreach (var element in source)
    {
        var raw = formatter(element);
        if (raw == null)
            continue;

        var trimmed = raw.AsSpan().Trim();
        if (trimmed.Length > 0)
        {
            items.Add(trimmed.ToString());
        }
    }

    if (items.Count == 0)
    {
        return string.Empty;
    }

    if (items.Count == 1)
    {
        return items[0];
    }

    var sb = new StringBuilder();
    for (int i = 0; i < items.Count - 1; i++)
    {
        if (i > 0)
        {
            sb.Append(separator);
        }
        sb.Append(items[i]);
    }
    sb.Append(" and ");
    sb.Append(items[^1]);
    return sb.ToString();
}

