/// <summary>
/// Core formatting method that converts a collection to a human-readable string.
/// </summary>
public virtual string Humanize<T>(
    IEnumerable<T> collection, Func<T, string?> objectFormatter, string separator)
{
    ArgumentNullException.ThrowIfNull(collection);
    ArgumentNullException.ThrowIfNull(objectFormatter);

    return HumanizeDisplayStrings(collection, objectFormatter, separator);
}

/// <summary>
/// Formats with an object-returning formatter, converting via .ToString().
/// </summary>
public string Humanize<T>(
    IEnumerable<T> collection, Func<T, object?> objectFormatter, string separator)
{
    ArgumentNullException.ThrowIfNull(collection);
    ArgumentNullException.ThrowIfNull(objectFormatter);

    // Fuse the two Select calls into one to avoid an extra enumerator allocation
    return HumanizeDisplayStrings(collection, item => objectFormatter(item)?.ToString(), separator);
}

/// <summary>
/// Single-pass collection formatting: applies the formatter, trims, filters blanks,
/// and builds the result string without intermediate LINQ chains.
/// </summary>
private string HumanizeDisplayStrings<T>(
    IEnumerable<T> source, Func<T, string?> formatter, string separator)
{
    var items = new List<string>();
    foreach (var element in source)
    {
        var raw = formatter(element);
        if (raw == null)
            continue;

        var trimmed = raw.AsSpan().Trim();
        if (trimmed.Length > 0)
        {
            items.Add(trimmed.ToString());
        }
    }

    if (items.Count == 0)
    {
        return string.Empty;
    }

    if (items.Count == 1)
    {
        return items[0];
    }

    var sb = new StringBuilder();
    for (int i = 0; i < items.Count - 1; i++)
    {
        if (i > 0)
        {
            sb.Append(separator);
        }
        sb.Append(items[i]);
    }
    sb.Append(" and ");
    sb.Append(items[^1]);
    return sb.ToString();
}

