1. using System.Globalization;
2. using System.Text;
3. 
4. namespace Textualizer;
5. 
6. /// <summary>
7. /// Specifies the unit of time for humanization purposes.
8. /// Values are ordered from largest to smallest.
9. /// </summary>
10. public enum TimeUnit
11. {
12.     /// <summary>Years.</summary>
13.     Year,
14.     /// <summary>Months.</summary>
15.     Month,
16.     /// <summary>Weeks.</summary>
17.     Week,
18.     /// <summary>Days.</summary>
19.     Day,
20.     /// <summary>Hours.</summary>
21.     Hour,
22.     /// <summary>Minutes.</summary>
23.     Minute,
24.     /// <summary>Seconds.</summary>
25.     Second,
26.     /// <summary>Milliseconds.</summary>
27.     Millisecond
28. }
29. 
30. /// <summary>
31. /// Provides extension methods for converting <see cref="TimeSpan"/> values to
32. /// human-readable strings with configurable precision, culture, and unit ranges.
33. /// </summary>
34. public static class TimeSpanReadabilityExtensions
35. {
36.     private const int DaysInAWeek = 7;
37.     private const double DaysInAYear = 365.2425;
38.     private const double DaysInAMonth = DaysInAYear / 12;
39. 
40.     // Pre-computed reversed array — no LINQ allocation at static init
41.     private static readonly TimeUnit[] TimeUnits =
42.     [
43.         TimeUnit.Millisecond,
44.         TimeUnit.Second,
45.         TimeUnit.Minute,
46.         TimeUnit.Hour,
47.         TimeUnit.Day,
48.         TimeUnit.Week,
49.         TimeUnit.Month,
50.         TimeUnit.Year,
51.     ];
52. 
53.     // Pre-computed unit name strings — avoids Enum.ToString() + ToLowerInvariant() per call
54.     private static readonly string[] UnitNamesSingular;
55.     private static readonly string[] UnitNamesPlural;
56. 
57.     static TimeSpanReadabilityExtensions()
58.     {
59.         var values = Enum.GetValues<TimeUnit>();
60.         UnitNamesSingular = new string[values.Length];
61.         UnitNamesPlural = new string[values.Length];
62.         foreach (var unit in values)
63.         {
64.             var name = unit.ToString().ToLowerInvariant();
65.             UnitNamesSingular[(int)unit] = name;
66.             UnitNamesPlural[(int)unit] = name + "s";
67.         }
68.     }
69. 
70.     /// <summary>
71.     /// Converts a <see cref="TimeSpan"/> to a human-readable string.
72.     /// </summary>
73.     /// <param name="timeSpan">The time span to humanize.</param>
74.     /// <param name="precision">The number of time units to include (e.g., 2 for "1 hour, 30 minutes").</param>
75.     /// <param name="culture">The culture for localized formatting. Uses current culture if null.</param>
76.     /// <param name="maxUnit">The largest time unit to display.</param>
77.     /// <param name="minUnit">The smallest time unit to display.</param>
78.     /// <param name="collectionSeparator">The separator between time parts (default: ", ").</param>
79.     /// <param name="countEmptyUnits">Whether empty units count toward precision.</param>
80.     /// <returns>A human-readable string representation of the time span.</returns>
81.     /// <example>
82.     /// <code>
83.     /// TimeSpan.FromMinutes(90).Humanize() => "1 hour"
84.     /// TimeSpan.FromMinutes(90).Humanize(precision: 2) => "1 hour, 30 minutes"
85.     /// TimeSpan.FromDays(1.5).Humanize(precision: 3) => "1 day, 12 hours"
86.     /// </code>
87.     /// </example>
88.     public static string Humanize(
89.         this TimeSpan timeSpan,
90.         int precision = 1,
91.         CultureInfo? culture = null,
92.         TimeUnit maxUnit = TimeUnit.Year,
93.         TimeUnit minUnit = TimeUnit.Millisecond,
94.         string? collectionSeparator = null,
95.         bool countEmptyUnits = false)
96.     {
97.         culture ??= CultureInfo.CurrentCulture;
98. 
99.         var timeParts = CreateTimeParts(timeSpan, maxUnit, minUnit, culture);
100. 
101.         if (IsContainingOnlyNullValue(timeParts))
102.         {
103.             return "no time";
104.         }
105. 
106.         timeParts = SetPrecisionOfTimeSpan(timeParts, precision, countEmptyUnits);
107. 
108.         return ConcatenateTimeSpanParts(timeParts, collectionSeparator ?? ", ");
109.     }
110. 
111.     /// <summary>
112.     /// Breaks down a TimeSpan into its component time part strings for each unit
113.     /// between maxUnit and minUnit.
114.     /// </summary>
115.     private static List<string?> CreateTimeParts(
116.         TimeSpan timeSpan, TimeUnit maxUnit, TimeUnit minUnit, CultureInfo culture)
117.     {
118.         var timeParts = new List<string?>(8);
119.         var totalDays = Math.Abs(timeSpan.TotalDays);
120. 
121.         foreach (var unit in TimeUnits)
122.         {
123.             if (unit < minUnit || unit > maxUnit)
124.             {
125.                 continue;
126.             }
127. 
128.             var value = unit switch
129.             {
130.                 TimeUnit.Year => (int)(totalDays / DaysInAYear),
131.                 TimeUnit.Month => (int)((totalDays % DaysInAYear) / DaysInAMonth),
132.                 TimeUnit.Week => (int)((totalDays % DaysInAMonth) / DaysInAWeek),
133.                 TimeUnit.Day => (int)(totalDays % DaysInAWeek),
134.                 TimeUnit.Hour => timeSpan.Hours,
135.                 TimeUnit.Minute => timeSpan.Minutes,
136.                 TimeUnit.Second => timeSpan.Seconds,
137.                 TimeUnit.Millisecond => timeSpan.Milliseconds,
138.                 _ => 0
139.             };
140. 
141.             timeParts.Add(value != 0 ? FormatTimePart(value, unit) : null);
142.         }
143. 
144.         return timeParts;
145.     }
146. 
147.     private static bool IsContainingOnlyNullValue(List<string?> timeParts)
148.     {
149.         for (int i = 0; i < timeParts.Count; i++)
